      "keystrokes": "gcc -static -o /app/reversed /app/mystery.c -lm && /app/mystery && cp /app/image.ppm /tmp/ref.ppm && /app/reversed && cp /app/image.ppm /tmp/mine.ppm && perl -e 'sub rp{open(F,$_[0]);<F>;<F>;<F>;my @p;while(<F>){push @p,split;}return @p;} my @r=rp("/tmp/ref.ppm");my @m=rp("/tmp/mine.ppm");my $n=scalar(@r);my $d=0;for my $i(0..$n-1){if($r[$i]!=$m[$i]){$d++;if($d<=10){my $px=$i/3;my $y=int($px/800);my $x=$px%800;print "idx $i x=$x y=$y ch=",$i%3," ref=$r[$i] mine=$m[$i]\n";}}}print "total=$n diffs=$d\n";'
",
      "duration": 1.0
    }
